type UpdateNodeHeartbeatParams struct {
	ID               pgtype.UUID
	LastFreeBytes    pgtype.Int8
	LastStoredBytes  pgtype.Int8
	SourceNebulaAddr string
}

func (q *Queries) UpdateNodeHeartbeat(ctx context.Context, arg UpdateNodeHeartbeatParams) (Node, error) {
	row := q.db.QueryRow(ctx, updateNodeHeartbeat,
		arg.ID,
		arg.LastFreeBytes,
		arg.LastStoredBytes,
		arg.SourceNebulaAddr,
	)
	var i Node
	err := row.Scan(
		&i.ID,
		&i.NebulaCertFingerprint,
		&i.FederationCertFingerprint,
		&i.DisplayName,
		&i.GeoDeclared,
		&i.CapacityBytes,
		&i.BandwidthBudgetBytesPerDay,
		&i.PolicyFilters,
		&i.Status,
		&i.ReputationScore,
		&i.JoinedAt,
		&i.LastSeenAt,
		&i.LastStatusChangeAt,
		&i.TrustState,
		&i.SelectedProtocol,
		&i.AdvertisedCapabilities,
		&i.RequiredCapabilities,
		&i.ClientVersion,
		&i.CertRevokedAt,
		&i.CertRotationStartedAt,
		&i.CertRotatedAt,
		&i.LastFreeBytes,
		&i.LastStoredBytes,
		&i.SourceNebulaAddr,
	)
	return i, err
}

const upsertPinAssignmentAssign = `-- name: UpsertPinAssignmentAssign :one
INSERT INTO pin_assignments (cid, node_id, state, generation)
VALUES ($1, $2, 'pending', 1)
ON CONFLICT (cid, node_id) DO UPDATE SET
    state       = 'pending',
    generation  = pin_assignments.generation + 1,
    acked_at    = NULL,
    assigned_at = now()
RETURNING assignment_id, generation
`

type UpsertPinAssignmentAssignParams struct {
	Cid    string
	NodeID pgtype.UUID
}

type UpsertPinAssignmentAssignRow struct {
	AssignmentID pgtype.UUID
	Generation   int64
}

func (q *Queries) UpsertPinAssignmentAssign(ctx context.Context, arg UpsertPinAssignmentAssignParams) (UpsertPinAssignmentAssignRow, error) {
	row := q.db.QueryRow(ctx, upsertPinAssignmentAssign, arg.Cid, arg.NodeID)
	var i UpsertPinAssignmentAssignRow
	err := row.Scan(&i.AssignmentID, &i.Generation)
	return i, err
}
